// class名が"example"で、data-test属性を持つ要素を全て取得
let elements = document.querySelectorAll('.example[data-test]');
// このコードを実行すると、class名が"example"で、data-test属性を持つ要素を全て取得することができます。

// 監視対象の要素を取得
let target = document.getElementById('target');

// MutationObserverのインスタンスを作成
let observer = new MutationObserver(function(mutations) {
  mutations.forEach(function(mutation) {
    console.log(mutation.target);
  });
});

// 監視の設定
let config = { attributes: true, childList: true, characterData: true };

// 監視を開始
observer.observe(target, config);

// このコードを実行すると、idが"target"の要素の変化を監視し、変化後の要素を取得することができます。

